  // Formula: nudge = deltaR * (cursorRayDir + sphericalDir)
  // This is the exact solution for pinning the focal-plane point to the cursor.
  const afterSnap = rig.snapshot();
  const deltaR = beforeSnap.radius - afterSnap.radius;
