  if (!ev.ctrlKey && Math.abs(ev.deltaX) > 1) {
    const normX = wheelDelta({ deltaY: ev.deltaX, deltaMode: ev.deltaMode });
    rig.pan(normX * 0.3, 0);
  }

  placeCamera();
}

function onKey(ev: KeyboardEvent): void {
  const target = ev.target as HTMLElement | null;
