1	/**
2	 * EDT-03 — 3D direct-manipulation handles (load-bearing slice).
3	 *
4	 * Same protocol as the plan-canvas grip system (EDT-01) but in the 3D
5	 * viewport. A grip provider, registered per element kind, returns the
6	 * grip descriptors for a given element. The viewport raycasts grips
7	 * before elements so they take precedence on hover.
8	 *
9	 * This module is the pure data layer (no Three.js imports), so it is
10	 * unit-testable without the renderer. The Viewport React component
11	 * imports the registry to drive its raycast layer; the engine writes
12	 * back via the `onCommit` payload's command type.
13	 *
14	 * Slice scope:
15	 *   - Wall: top + bottom edge handles → topConstraintOffsetMm /
16	 *     baseConstraintOffsetMm (the load-bearing case from the seeded
17	 *     SSW viewpoint demo).
18	 *
19	 * Roof, floor, column / beam, and door / window grips are deferred to
20	 * follow-ups; the registration protocol below is forward-compatible
21	 * (any kind can opt-in by calling `register3dGripProvider`).
22	 */
23	
24	export type Grip3dAxis = 'x' | 'y' | 'z';
25	
26	export type Grip3dDescriptor = {
27	  /** Identifier unique within the parent element. */
28	  id: string;
29	  /**
30	   * Which property the grip mutates. Used by the renderer to pick a
31	   * glow colour and by the engine to dispatch the right command.
32	   */
33	  role: string;
34	  /** World-space anchor (millimetres). */
35	  position: { xMm: number; yMm: number; zMm: number };
36	  /** Drag axis in world space. */
37	  axis: Grip3dAxis;
38	  /** Inclusive drag range in millimetres relative to start position. */
39	  rangeMm: { minMm: number; maxMm: number };
40	  /**
41	   * Pure mapping: live drag-distance → property delta payload that the
42	   * Viewport overlay uses to render the live preview.
43	   */
44	  onDrag: (deltaMm: number) => Grip3dDragPayload;
45	  /**
46	   * Pure mapping: final drag-distance → engine-command spec. The
47	   * Viewport hands this to the dispatcher; the engine validates and
48	   * either commits or rejects (constraints — EDT-02).
49	   */
50	  onCommit: (deltaMm: number) => Grip3dCommitSpec | null;
51	};
52	
53	export type Grip3dDragPayload = {
54	  elementId: string;
55	  property: string;
56	  valueMm: number;
57	};
58	
59	export type Grip3dCommitSpec = {
60	  type: string;
61	  payload: Record<string, unknown>;
62	};
63	
64	export type Grip3dProvider<E = Record<string, unknown>> = (element: E) => Grip3dDescriptor[];
65	
66	const REGISTRY = new Map<string, Grip3dProvider>();
67	
68	export function register3dGripProvider<E = Record<string, unknown>>(
69	  kind: string,
70	  provider: Grip3dProvider<E>,
71	): void {
72	  REGISTRY.set(kind, provider as Grip3dProvider);
73	}
74	
75	export function unregister3dGripProvider(kind: string): void {
76	  REGISTRY.delete(kind);
77	}
78	
79	export function gripsFor(element: { kind?: string }): Grip3dDescriptor[] {
80	  if (!element || !element.kind) return [];
81	  const provider = REGISTRY.get(element.kind);
82	  if (!provider) return [];
83	  return provider(element as Record<string, unknown>);
84	}
85	
86	export function clear3dGripProviders(): void {
87	  REGISTRY.clear();
88	}
89	
90	/**
91	 * Numerical helper used by every provider — clamp a drag delta to the
92	 * descriptor's allowed range. Pure so it is independently testable.
93	 */
94	export function clampDragDelta(deltaMm: number, range: { minMm: number; maxMm: number }): number {
95	  if (Number.isNaN(deltaMm)) return 0;
96	  if (deltaMm < range.minMm) return range.minMm;
97	  if (deltaMm > range.maxMm) return range.maxMm;
98	  return deltaMm;
99	}
100	
101	// ---------- Wall provider (load-bearing slice) ------------------------------
102	
103	type WallElementShape = {
104	  id: string;
105	  kind: 'wall';
106	  start: { xMm: number; yMm: number };
107	  end: { xMm: number; yMm: number };
108	  heightMm: number;
109	  baseElevationMm?: number;
110	  baseConstraintOffsetMm?: number;
111	  topConstraintOffsetMm?: number;
112	};
113	
114	const MIN_WALL_HEIGHT_MM = 100;
115	const MAX_WALL_HEIGHT_MM = 30_000;
116	
117	/**
118	 * Anchor 3D handles at the wall's plan midpoint (so the grip is
119	 * visible on the cleanest face). Vertical offsets land at the current
120	 * top / base elevations of the wall.
121	 */
122	export function wallGripProvider(wall: WallElementShape): Grip3dDescriptor[] {
123	  const midX = (wall.start.xMm + wall.end.xMm) / 2;
124	  const midY = (wall.start.yMm + wall.end.yMm) / 2;
125	  const baseElevation = wall.baseElevationMm ?? 0;
126	  const baseOffset = wall.baseConstraintOffsetMm ?? 0;
127	  const topOffset = wall.topConstraintOffsetMm ?? 0;
128	  const baseZ = baseElevation + baseOffset;
129	  const topZ = baseElevation + wall.heightMm + topOffset;
130	
131	  const topRange = {
132	    minMm: -(wall.heightMm - MIN_WALL_HEIGHT_MM),
133	    maxMm: MAX_WALL_HEIGHT_MM - wall.heightMm,
134	  };
135	  const baseRange = {
136	    minMm: -wall.heightMm + MIN_WALL_HEIGHT_MM,
137	    maxMm: wall.heightMm - MIN_WALL_HEIGHT_MM,
138	  };
139	
140	  const topDescriptor: Grip3dDescriptor = {
141	    id: `${wall.id}/top`,
142	    role: 'topConstraintOffsetMm',
143	    position: { xMm: midX, yMm: midY, zMm: topZ },
144	    axis: 'z',
145	    rangeMm: topRange,
146	    onDrag: (delta) => ({
147	      elementId: wall.id,
148	      property: 'topConstraintOffsetMm',
149	      valueMm: topOffset + clampDragDelta(delta, topRange),
150	    }),
151	    onCommit: (delta) => {
152	      const clamped = clampDragDelta(delta, topRange);
153	      if (clamped === 0) return null;
154	      return {
155	        type: 'updateElementProperty',
156	        payload: {
157	          elementId: wall.id,
158	          property: 'topConstraintOffsetMm',
159	          valueMm: topOffset + clamped,
160	        },
161	      };
162	    },
163	  };
164	
165	  const baseDescriptor: Grip3dDescriptor = {
166	    id: `${wall.id}/base`,
167	    role: 'baseConstraintOffsetMm',
168	    position: { xMm: midX, yMm: midY, zMm: baseZ },
169	    axis: 'z',
170	    rangeMm: baseRange,
171	    onDrag: (delta) => ({
172	      elementId: wall.id,
173	      property: 'baseConstraintOffsetMm',
174	      valueMm: baseOffset + clampDragDelta(delta, baseRange),
175	    }),
176	    onCommit: (delta) => {
177	      const clamped = clampDragDelta(delta, baseRange);
178	      if (clamped === 0) return null;
179	      return {
180	        type: 'updateElementProperty',
181	        payload: {
182	          elementId: wall.id,
183	          property: 'baseConstraintOffsetMm',
184	          valueMm: baseOffset + clamped,
185	        },
186	      };
187	    },
188	  };
189	
190	  return [topDescriptor, baseDescriptor];
191	}
192	
193	register3dGripProvider('wall', wallGripProvider as Grip3dProvider);

